SELECT DISTINCT n.* FROM project_notification n
INNER JOIN project_notification_recipient r ON r.notification_id = n.notification_id
WHERE r.user_id = #{userId} AND n.del_flag = '0' AND r.del_flag = '0'

    AND n.type = #{type}


    AND n.status = #{status}


    AND (n.title LIKE CONCAT('%', #{keyword}, '%') OR n.content LIKE CONCAT('%', #{keyword}, '%'))

ORDER BY n.create_time DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(DISTINCT n.notification_id) FROM project_notification n
INNER JOIN project_notification_recipient r ON r.notification_id = n.notification_id
WHERE r.user_id = #{userId} AND n.del_flag = '0' AND r.del_flag = '0'

    AND n.type = #{type}


    AND n.status = #{status}


    AND (n.title LIKE CONCAT('%', #{keyword}, '%') OR n.content LIKE CONCAT('%', #{keyword}, '%'))

